from collections import deque

def solve(grid: list[list[int]], k: int) -> int:
    count = 0
    m = len(grid)
    if m == 0:
        return 0
    n = len(grid[0])
    dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    for i in range(m):
        for j in range(n):
            if grid[i][j] > 0:
                sum_val = grid[i][j]
                grid[i][j] = 0
                queue = deque()
                queue.append((i, j))
                while queue:
                    x, y = queue.popleft()
                    for dx, dy in dirs:
                        nx = x + dx
                        ny = y + dy
                        if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] > 0:
                            sum_val += grid[nx][ny]
                            grid[nx][ny] = 0
                            queue.append((nx, ny))
                if sum_val % k == 0:
                    count += 1
    return count
```

